using BotFramework.Discord.Commands;using BotFramework.Discord.Routing;using Games.Blackjack.Contracts;
namespace Games.Blackjack.Discord;
public sealed class BlackjackDiscordHandler(IBlackjackClient client):IDiscordMessageHandler{public bool CanHandle(DiscordMessageContext c)=>DiscordCommand.Is(c,"blackjack","bj");public async Task HandleAsync(DiscordMessageContext c){var p=DiscordCommand.Parts(c);var uid=DiscordCommand.UserId(c);if(p.Length<2){await DiscordCommand.ReplyAsync(c,"`blackjack start <bet>` | `blackjack hit|stand|double|state`");return;}object r;switch(p[1].ToLowerInvariant()){case "start" when p.Length>=3&&int.TryParse(p[2],out var bet)&&bet>0:r=await client.StartAsync(uid,DiscordCommand.DisplayName(c),DiscordCommand.ScopeId(c),bet,c.Message.Id.ToString(),c.CancellationToken);break;case "hit":r=await client.HitAsync(uid,c.CancellationToken);break;case "stand":r=await client.StandAsync(uid,c.CancellationToken);break;case "double":r=await client.DoubleAsync(uid,c.CancellationToken);break;case "state":r=await client.GetStateAsync(uid,c.CancellationToken);break;default:await DiscordCommand.ReplyAsync(c,"`blackjack start <bet>` | `blackjack hit|stand|double|state`");return;}await DiscordCommand.ReplyResultAsync(c,r,"Blackjack");}}
public static class BlackjackDiscordModule{public static IServiceCollection AddBlackjackDiscord(this IServiceCollection s)=>s.AddScoped<IDiscordMessageHandler,BlackjackDiscordHandler>();}
